class Solution(object):
    def maxDivScore(self, nums, divisors):
        best_d = min(divisors)
        best_c = sum(1 for x in nums if x % best_d == 0)
        for d in divisors:
            c = sum(1 for x in nums if x % d == 0)
            if c > best_c or (c == best_c and d < best_d):
                best_c, best_d = c, d
        return best_d
